-- ----------------------------
-- Table structure for app_ui_elements
-- ----------------------------
DROP TABLE IF EXISTS `app_ui_elements`;
CREATE TABLE `app_ui_elements`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `creation_date` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `created_by` bigint NULL DEFAULT NULL,
  `updation_date` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_by` bigint NULL DEFAULT NULL,
  `enabled_flag` tinyint(1) NOT NULL DEFAULT 1,
  `trace_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `page_id` bigint NOT NULL COMMENT '页面 id',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '元素名',
  `locate_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'id' COMMENT '定位类型',
  `locate_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '定位值',
  `num` int NULL DEFAULT 0 COMMENT '排序',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_app_ui_elements_page`(`page_id` ASC) USING BTREE,
  INDEX `idx_app_ui_elements_user`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'APP UI 元素' ROW_FORMAT = DYNAMIC;

