DROP TABLE IF EXISTS `web_management_result_lists`;
CREATE TABLE `web_management_result_lists`  (
  `task_name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '任务名称',
